def load_tests(loader, tests, pattern):
    tests.addTest(doctest.DocTestSuite())
    return tests


# --- test body ---
def _check_error(code, errtext, filename='<testcase>', mode='exec', subclass=None, lineno=None, offset=None, end_lineno=None, end_offset=None):
    """Check that compiling code raises SyntaxError with errtext.

        errtest is a regular expression that must be present in the
        test of the exception raised.  If subclass is specified it
        is the expected subclass of SyntaxError (e.g. IndentationError).
        """
    try:
        compile(code, filename, mode)
    except SyntaxError as err:
        if subclass and (not isinstance(err, subclass)):

            raise AssertionError('SyntaxError is not a %s' % subclass.__name__)
        mo = re.search(errtext, str(err))
        if mo is None:

            raise AssertionError('SyntaxError did not contain %r' % (errtext,))

        assert err.filename == filename
        if lineno is not None:

            assert err.lineno == lineno
        if offset is not None:

            assert err.offset == offset
        if end_lineno is not None:

            assert err.end_lineno == end_lineno
        if end_offset is not None:

            assert err.end_offset == end_offset
    else:

        raise AssertionError('compile() did not raise SyntaxError')
msg = 'not properly in loop'
_check_error('if 0: continue', msg, lineno=1)
_check_error('if 0: continue\nelse:  x=1', msg, lineno=1)
_check_error('if 1: pass\nelse: continue', msg, lineno=2)
_check_error('class C:\n  if 0: continue', msg, lineno=2)
_check_error('class C:\n  if 1: pass\n  else: continue', msg, lineno=3)
_check_error('with object() as obj:\n    continue', msg, lineno=2)
print("SyntaxTestCase::test_continue_outside_loop: ok")
